import{_ as t,o as r,c as a,a5 as o}from"./chunks/framework.RItJKYA7.js";const u=JSON.parse('{"title":"Integration paths","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/integration-paths.md","filePath":"concepts/integration-paths.md"}'),n={name:"concepts/integration-paths.md"};function i(s,e,l,h,d,c){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="integration-paths" tabindex="-1">Integration paths <a class="header-anchor" href="#integration-paths" aria-label="Permalink to &quot;Integration paths&quot;">​</a></h1><p>Service providers integrate with Platform Mesh by exposing declarative APIs and reconciling consumer requests into real services. There are two paths today and a third under development. All paths produce the same consumer experience: declarative APIs available through APIExport and APIBinding.</p><h2 id="choose-a-path" tabindex="-1">Choose a path <a class="header-anchor" href="#choose-a-path" aria-label="Permalink to &quot;Choose a path&quot;">​</a></h2><p>Use <strong>api-syncagent</strong> when the provider already exposes Kubernetes CRDs and the standard spec-down / status-up sync pattern is enough.</p><p>Use <strong>multicluster-runtime</strong> when the provider needs custom sync logic, non-CRD APIs, or reconciliation built directly into a provider controller.</p><p>Both paths require a Kubernetes operator that reconciles your service&#39;s resources. The paths differ in <em>how</em> synchronization between kcp and the service cluster is handled, not in whether you need an operator.</p><h2 id="comparison" tabindex="-1">Comparison <a class="header-anchor" href="#comparison" aria-label="Permalink to &quot;Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Path</th><th>Best fit</th><th>Provider effort</th></tr></thead><tbody><tr><td>api-syncagent</td><td>Existing CRD-based service APIs</td><td>Operator + deploy the sync agent; sync handled by the agent</td></tr><tr><td>multicluster-runtime</td><td>Custom controllers, non-CRD APIs, complex sync logic</td><td>Operator built with mcr libraries; sync built into the operator</td></tr></tbody></table><h2 id="kube-bind-work-in-progress" tabindex="-1">kube-bind (work in progress) <a class="header-anchor" href="#kube-bind-work-in-progress" aria-label="Permalink to &quot;kube-bind (work in progress)&quot;">​</a></h2><p><code>kube-bind</code> will serve a dual role in Platform Mesh:</p><ul><li><strong>Provider side</strong> — let vanilla Kubernetes clusters connect to the mesh as service providers and publish their APIs into Platform Mesh.</li><li><strong>Consumer side</strong> — let consumers extend their Platform Mesh control plane to their own workload clusters so resources from a consumer&#39;s account appear on the workload cluster as if they were created there, enabling a fully local development and deployment experience.</li></ul><p>This integration path is currently under development. See the <a href="./interaction-patterns/provider-to-consumer.html">interaction patterns</a> for how kube-bind will fit into provider-to-consumer and provider-to-provider topologies.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./integration/api-syncagent.html">api-syncagent</a></li><li><a href="./integration/multicluster-runtime.html">multicluster-runtime</a></li><li><a href="./api-sharing.html">API sharing</a></li><li><a href="./interaction-patterns/provider-to-consumer.html">Provider to consumer</a></li></ul>',14)])])}const m=t(n,[["render",i]]);export{u as __pageData,m as default};
